//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Footnote/endnote reference plumbing and content stories".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 about how Word consumes and round-trips
//! footnote/endnote *reference* runs in the body story. A FAILING assertion
//! means stemma diverges from Word — i.e. it encodes a REAL Word-compliance
//! gap, not a thing to be "made to pass" by weakening the test. Fix the engine
//! at the source, or accept the failure as a confirmed finding.
//!
//! Methodology guardrails honoured here:
//!   * `xmlContains` / `xmlOmits` assertions run against `reserialize()`, which
//!     reflects stemma's verbatim-preservation contract (untouched opaque
//!     content is round-tripped byte-verbatim). They are used ONLY for "the
//!     reference run and its id/style survive serialization", which IS what the
//!     verbatim contract promises.
//!   * Consumption semantics ("the body text excludes the note story",
//!     "reject-all == baseline") are asserted on the READ side via
//!     `read_accepted()` / `read_rejected()` + `to_text()`.
//!   * Word's narrower note-id ceiling (<=32767) is an "opens-clean" validity
//!     question, asserted via `stemma::api::validate`.

use std::io::{Cursor, Read, Write};
use zip::write::FileOptions;

// ─── Prelude: minimal-docx plumbing (mirrors the shared spec-suite prelude) ───

/// Build a valid minimal `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (paragraphs etc.); `extra_parts` are additional
/// `(part_name, xml)` entries placed into the zip, with a matching content-type
/// Override emitted for the known WordprocessingML parts (styles, numbering).
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build content-type overrides for extra parts we understand.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = match *name {
            "word/styles.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
            }
            "word/numbering.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
            }
            "word/footnotes.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.footnotes+xml")
            }
            "word/endnotes.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.endnotes+xml")
            }
            _ => None,
        };
        if let Some(ct) = ct {
            overrides.push_str(&format!(
                r#"<Override PartName="/{name}" ContentType="{ct}"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, xml) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return the contents of `word/document.xml`.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize (no-op roundtrip) → return the re-emitted `word/document.xml`.
/// For UNTOUCHED content this reflects stemma's verbatim-preservation contract.
fn reserialize(bytes: &[u8]) -> String {
    let doc = stemma::api::Document::parse(bytes).expect("parse");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

