#[test]
fn footnote_reference_run_preserves_rstyle_and_id_through_roundtrip() {
    let body = r#"<w:p><w:r><w:rPr><w:rStyle w:val="FootnoteReference"/></w:rPr><w:footnoteReference w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:footnoteReference w:id="1""#),
        "ECMA-376 §17.11.14 / ISO 29500-1 §17.11.14 — refs: the footnoteReference w:id linkage is load-bearing and stemma preserves untouched opaque content verbatim, so the id must survive the roundtrip; got XML:\n{xml}"
    );
    assert!(
        xml.contains(r#"w:val="FootnoteReference""#),
        "ECMA-376 §17.11.14 / ISO 29500-1 §17.11.14 — refs: canonical markup binds the reference run to the FootnoteReference character style; a verbatim roundtrip must retain it; got XML:\n{xml}"
    );
}

// check_footnote_endnote_id_range validates the in-body
// footnoteReference/endnoteReference ids (§17.11.14), not just the note
// definitions — an id past Word's 32767 ceiling is flagged.
#[test]
fn footnote_reference_id_above_word_max_not_clean() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Referenced text.</w:t></w:r><w:r><w:footnoteReference w:id="40000"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "MS-OI29500 §2.1.300/§2.1.302, ISO 29500-1 §17.11.14/§17.18.10 — refs: Word only accepts note ids in [-2147483648, 32767]; id=40000 is outside Word's range so the document must NOT open clean (validate must report an error). Got ok={} issues={:?}",
        report.ok, report.issues
    );
}

// endnoteReference ids are range-checked too (same rule).
#[test]
fn endnote_reference_id_above_word_max_not_clean() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Referenced text.</w:t></w:r><w:r><w:endnoteReference w:id="40000"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "MS-OI29500 §2.1.300/§2.1.302, ISO 29500-1 §17.11.7/§17.18.10 — refs: Word's endnote id ceiling is 32767 (same as footnotes); endnoteReference id=40000 is outside Word's range so the document must NOT open clean. Got ok={} issues={:?}",
        report.ok, report.issues
    );
}

#[test]
fn footnote_reference_custommarkfollows_false_preserved_verbatim() {
    let body = r#"<w:p><w:r><w:t>Text</w:t></w:r><w:r><w:rPr><w:rStyle w:val="FootnoteReference"/></w:rPr><w:footnoteReference w:customMarkFollows="0" w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:customMarkFollows="0""#),
        "ECMA-376 §17.11.14, Annex A CT_FtnEdnRef — refs: verbatim-preservation contract means an explicitly authored, default-equivalent customMarkFollows=\"0\" is opaque markup the engine must round-trip unchanged, not collapse to the omitted default; got XML:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.11.14, Annex A CT_FtnEdnRef — refs: ST_OnOff admits 0/false, so customMarkFollows=\"0\" on CT_FtnEdnRef is schema-valid and must open without repair. Got ok={} issues={:?}",
        report.ok, report.issues
    );
}

