#[test]
fn endnote_reference_custommarkfollows_preserved_verbatim() {
    let body = r#"<w:p><w:r><w:t>This text is followed by an endnote</w:t></w:r><w:r><w:rPr><w:rStyle w:val="EndnoteReference"/></w:rPr><w:endnoteReference w:customMarkFollows="true" w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:customMarkFollows="true""#),
        "ECMA-376 §17.11.7 / ISO 29500-1 §17.11.7, Annex A CT_FtnEdnRef — refs: customMarkFollows is an authored numbering-suppression flag on CT_FtnEdnRef; a verbatim-preserving engine must re-emit it on reserialize for endnotes just as for footnotes; got XML:\n{xml}"
    );
    assert!(
        xml.contains("w:endnoteReference"),
        "ECMA-376 §17.11.7 / ISO 29500-1 §17.11.7 — refs: the endnoteReference run must survive the roundtrip intact (the reference linkage is the body half of the endnote per §17.11); got XML:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.11.7, Annex A CT_FtnEdnRef — refs: endnoteReference is CT_FtnEdnRef and customMarkFollows is an optional ST_OnOff attribute of that type, so the document is schema-valid and opens without repair. Got ok={} issues={:?}",
        report.ok, report.issues
    );
}

#[test]
fn footnote_reference_in_body_contributes_one_object_char_not_note_text() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Referenced text</w:t></w:r><w:r><w:rPr><w:rStyle w:val="FootnoteReference"/></w:rPr><w:footnoteReference w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = stemma::api::Document::parse(&b).expect("parse");
    let text = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        text.trim(),
        "Referenced text\u{FFFC}",
        "ECMA-376 §17.11/§17.11.14 / ISO 29500-1 §17.11.14 — refs: only a reference mark sits in the body; the note story prose is separate, so the accepted body text is the run text plus exactly one object-replacement char for the anchor, never the note body. Got {text:?}"
    );
}

